    // Supply invariant harness: swap — whirlpool.total_supply must increase by amount
    #[kani::proof]
    fn verify_swap_supply() {
        let amount: u64 = kani::any();
        let other_amount_threshold: u64 = kani::any();
        let sqrt_price_limit: u64 = kani::any();
        let amount_specified_is_input: bool = kani::any();
        let a_to_b: bool = kani::any();
        let mut ctx: SwapCtx = kani::any();
        kani::assume(ctx.is_signer);
        kani::assume(ctx.whirlpool.total_supply <= u64::MAX / 2);
        kani::assume(amount <= u64::MAX / 2);
        let pre_total_supply = ctx.whirlpool.total_supply;
        let result = swap(&mut ctx, amount, other_amount_threshold, sqrt_price_limit, amount_specified_is_input, a_to_b);
        if result.is_ok() {
            assert!(
                ctx.whirlpool.total_supply == pre_total_supply + amount,
                "SUPPLY_INVARIANT: total_supply not correctly updated after successful swap"
            );
        }
    }

