    // Auth harness: set_config_feature_flag — non-owner must always be rejected
    #[kani::proof]
    fn verify_set_config_feature_flag_auth() {
        let feature_flag: u64 = kani::any();
        let mut ctx: SetConfigFeatureFlagCtx = kani::any();
        kani::assume(ctx.is_signer);
        // Force the attack scenario: caller is NOT the rightful owner
        kani::assume(ctx.authority != ctx.whirlpools_config.authority);
        kani::assume(feature_flag <= u64::MAX / 2);
        kani::assume(ctx.whirlpools_config.total_supply >= feature_flag);
        kani::assume(ctx.whirlpools_config.total_supply <= u64::MAX / 2);
        let result = set_config_feature_flag(&mut ctx, feature_flag);
        assert!(
            result.is_err(),
            "AUTH_VIOLATION: set_config_feature_flag succeeded without matching authority"
        );
    }

